class DecisionTreeFtmoAlpha(BaseStrategy):
    name = "decision_tree_ftmo_5m_30m_4h"

    def compute_signal(self, ctx) -> int:
        g = lambda col, tf: ctx.ind(col, tf)
        x = _features(g)
        for v in x:
            if v is None or not math.isfinite(v):
                return ALPHA_INACTIVE          # warm-up / missing -> abstain
        s = evaluate_tree(x)
        return ALPHA_BUY if s > 0 else (ALPHA_SELL if s < 0 else ALPHA_INACTIVE)


